import{_ as i,o as t,c as n,a9 as l}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"cn-font-split 的 DLL 为什么没下载","description":"","frontmatter":{},"headers":[],"relativePath":"工程化/Vue/cn-font-split-DLL未下载原因与处理.md","filePath":"工程化/Vue/cn-font-split-DLL未下载原因与处理.md","lastUpdated":1777106511000}'),e={name:"工程化/Vue/cn-font-split-DLL未下载原因与处理.md"};function a(o,s,d,p,h,c){return t(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="cn-font-split-的-dll-为什么没下载" tabindex="-1">cn-font-split 的 DLL 为什么没下载 <a class="header-anchor" href="#cn-font-split-的-dll-为什么没下载" aria-label="Permalink to “cn-font-split 的 DLL 为什么没下载”">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to “现象”">​</a></h2><p><code>dist</code> 下没有 <code>libffi-x86_64-pc-windows-msvc.dll</code>，运行时报错：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ERR_FFI: Failed to load shared library: 找不到指定的模块。</span></span>
<span class="line"><span>lib: &#39;...\\cn-font-split\\dist\\libffi-x86_64-pc-windows-msvc.dll&#39;</span></span></code></pre></div><p>该 DLL <strong>不会随 npm 包发布</strong>，需要由安装后的 <strong>postinstall 脚本</strong> 从 GitHub Releases 下载到 <code>cn-font-split/dist/</code>。<br> 若 postinstall 没成功执行或下载失败，<code>dist</code> 下就不会有该文件。</p><hr><h2 id="可能原因" tabindex="-1">可能原因 <a class="header-anchor" href="#可能原因" aria-label="Permalink to “可能原因”">​</a></h2><h3 id="_1-postinstall-失败被-吞掉-最常见" tabindex="-1">1. postinstall 失败被“吞掉”（最常见） <a class="header-anchor" href="#_1-postinstall-失败被-吞掉-最常见" aria-label="Permalink to “1. postinstall 失败被“吞掉”（最常见）”">​</a></h3><p><code>cn-font-split</code> 的 <code>package.json</code> 里：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;postinstall&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node ./dist/cli.js i default || node -v&quot;</span></span></code></pre></div><p>含义是：先执行 <code>node ./dist/cli.js i default</code> 下载 DLL，<strong>若失败就执行 <code>node -v</code></strong>。<br> 因此只要 <code>node -v</code> 能跑，整个脚本的退出码就是 0，pnpm 会认为安装成功，<strong>下载失败时不会报错</strong>。</p><ul><li>若网络不通、PowerShell 报错、写入权限等问题导致下载失败，你这边看不到任何安装错误，但 DLL 不会出现。</li></ul><h3 id="_2-pnpm-未执行依赖的-postinstall-pnpm-10" tabindex="-1">2. pnpm 未执行依赖的 postinstall（pnpm 10+） <a class="header-anchor" href="#_2-pnpm-未执行依赖的-postinstall-pnpm-10" aria-label="Permalink to “2. pnpm 未执行依赖的 postinstall（pnpm 10+）”">​</a></h3><p>从 pnpm 10 起，出于安全考虑，<strong>依赖包的生命周期脚本（含 postinstall）默认不执行</strong>。<br> 只有通过配置允许的包才会跑脚本。</p><ul><li>若未为 <code>cn-font-split</code> 或全局开启“允许构建/脚本”，其 postinstall <strong>根本不会运行</strong>，DLL 也就不会下载。</li><li>项目当前没有 <code>.npmrc</code> 或 <code>pnpm-workspace.yaml</code> 里的 等配置，在 pnpm 10+ 下就会属于“未允许”的依赖。</li></ul><h3 id="_3-从-store-恢复时未再跑-postinstall" tabindex="-1">3. 从 store 恢复时未再跑 postinstall <a class="header-anchor" href="#_3-从-store-恢复时未再跑-postinstall" aria-label="Permalink to “3. 从 store 恢复时未再跑 postinstall”">​</a></h3><p>pnpm 从<strong>本地 store 恢复</strong>已缓存的包时，有可能<strong>不再执行</strong>该包的 postinstall（视 pnpm 版本与配置而定）。</p><ul><li>第一次安装时若因上述 1 或 2 导致没下载成功，之后多次 <code>pnpm install</code> 可能一直用缓存的包，且不再跑 postinstall，DLL 会一直缺失。</li></ul><h3 id="_4-网络或环境" tabindex="-1">4. 网络或环境 <a class="header-anchor" href="#_4-网络或环境" aria-label="Permalink to “4. 网络或环境”">​</a></h3><ul><li>下载地址为：<code>https://github.com/KonghaYao/cn-font-split/releases/download/&lt;version&gt;/libffi-x86_64-pc-windows-msvc.dll</code>（版本号由 init.ps1 里请求 ungh.cc 得到）。</li><li>若 GitHub / ungh.cc 访问不了或被拦截，下载会失败；同样因为 <code>|| node -v</code>，安装不会报错。</li><li>Windows 下 postinstall 会通过 <code>powershell -ExecutionPolicy Bypass -File ...\\init.ps1 i default</code> 执行；若 PowerShell 策略或路径异常，也可能静默失败。</li></ul><hr><h2 id="处理办法" tabindex="-1">处理办法 <a class="header-anchor" href="#处理办法" aria-label="Permalink to “处理办法”">​</a></h2><h3 id="办法一-手动下载-dll-推荐-立刻可用" tabindex="-1">办法一：手动下载 DLL（推荐，立刻可用） <a class="header-anchor" href="#办法一-手动下载-dll-推荐-立刻可用" aria-label="Permalink to “办法一：手动下载 DLL（推荐，立刻可用）”">​</a></h3><p>在项目根目录执行（会往当前项目使用的 <code>cn-font-split</code> 的 <code>dist</code> 里下载）：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cn-font-split</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span></span></code></pre></div><p>或直接指定包路径：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node_modules/.pnpm/cn-font-split@7.4.1/node_modules/cn-font-split/dist/cli.js</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span></span></code></pre></div><p>执行成功后，<code>node_modules\\.pnpm\\cn-font-split@7.4.1\\node_modules\\cn-font-split\\dist\\</code> 下会出现 <code>libffi-x86_64-pc-windows-msvc.dll</code>。</p><p>若 GitHub 访问不稳定，可先设置镜像再执行（示例）：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CN_FONT_SPLIT_GH_HOST=https://ghproxy.com/https://github.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cn-font-split</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span></span></code></pre></div><h3 id="allowbuilds-onlybuiltdependencies-区别-pnpm-10" tabindex="-1"><code>allowBuilds</code> / <code>onlyBuiltDependencies</code> 区别（pnpm 10+） <a class="header-anchor" href="#allowbuilds-onlybuiltdependencies-区别-pnpm-10" aria-label="Permalink to “allowBuilds / onlyBuiltDependencies 区别（pnpm 10+）”">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>含义</th><th>说明</th></tr></thead><tbody><tr><td><strong>onlyBuiltDependencies</strong></td><td>配置项（白名单）</td><td>写在 <code>pnpm-workspace.yaml</code> 或 <code>.npmrc</code> 里。<strong>只有</strong>列在此处的包才会在安装时执行生命周期脚本（如 postinstall）；未列出的依赖默认不执行。适合只允许少数信任的包跑脚本。</td></tr><tr><td><strong>allowBuilds</strong></td><td>操作/概念</td><td>不是单独一个配置键，而是「允许某包执行构建脚本」这一行为。通过 <code>pnpm approve-builds</code> 或 <code>pnpm add --allow-build &lt;pkg&gt;</code> 会把包<strong>写入</strong> <code>onlyBuiltDependencies</code>。文档里说的 “use allowBuilds” 即指：用白名单方式允许构建，而白名单就是 onlyBuiltDependencies。</td></tr><tr><td><strong>dangerouslyAllowAllBuilds</strong></td><td>配置项（全局放开）</td><td>设为 <code>true</code> 时，<strong>所有</strong>依赖都会执行 postinstall 等脚本。安全风险大，不推荐。</td></tr><tr><td><strong>ignoredBuiltDependencies</strong></td><td>配置项（黑名单）</td><td>显式禁止执行构建脚本的包列表；与 onlyBuiltDependencies 二选一使用。</td></tr></tbody></table><p>总结：要允许 <code>cn-font-split</code> 跑 postinstall，应配置 <strong>onlyBuiltDependencies</strong>（或通过 approve-builds 间接写入）；不要用 dangerouslyAllowAllBuilds。</p><hr><h3 id="办法二-让-pnpm-每次安装时都跑-postinstall-pnpm-10" tabindex="-1">办法二：让 pnpm 每次安装时都跑 postinstall（pnpm 10+） <a class="header-anchor" href="#办法二-让-pnpm-每次安装时都跑-postinstall-pnpm-10" aria-label="Permalink to “办法二：让 pnpm 每次安装时都跑 postinstall（pnpm 10+）”">​</a></h3><p>若希望以后 <code>pnpm install</code> 时自动下载 DLL，需要让 pnpm 对 <code>cn-font-split</code> 执行生命周期脚本。</p><p>在项目根目录新建或修改 <strong><code>.npmrc</code></strong> 或 <strong><code>package.json</code></strong>。</p><p><strong>单个模块（.npmrc）：</strong></p><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">onlyBuiltDependencies</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=cn-font-split</span></span></code></pre></div><p><strong>多个模块</strong> 有两种写法：</p><ol><li><strong>.npmrc</strong>（数组写法，每行一个）：</li></ol><div class="language-ini"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">onlyBuiltDependencies[]=cn-font-split</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">onlyBuiltDependencies[]=esbuild</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">onlyBuiltDependencies[]=@swc/core</span></span></code></pre></div><ol start="2"><li><strong>package.json</strong>（在根目录的 <code>package.json</code> 里增加 <code>pnpm</code> 字段）：</li></ol><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;pnpm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;onlyBuiltDependencies&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cn-font-split&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;esbuild&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@swc/core&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>然后删除 <code>node_modules</code> 和 lockfile 中对该包的缓存后重新安装（或先执行一次 <code>pnpm rebuild cn-font-split</code>），这样会在安装/重建时再次跑 postinstall 并尝试下载 DLL。<br> 若仍因网络等原因失败，再用手动命令（办法一）补下即可。</p><h3 id="办法三-开发环境不依赖该-dll-当前项目已采用" tabindex="-1">办法三：开发环境不依赖该 DLL（当前项目已采用） <a class="header-anchor" href="#办法三-开发环境不依赖该-dll-当前项目已采用" aria-label="Permalink to “办法三：开发环境不依赖该 DLL（当前项目已采用）”">​</a></h3><p>本站已在 <code>.vitepress/config.ts</code> 中配置：<strong>仅在 production 构建时启用 <code>vite-plugin-font</code></strong>（即仅 build 时用 <code>cn-font-split</code>），dev 时不用。</p><p>因此：</p><ul><li><strong>开发</strong>：<code>pnpm dev</code> 不加载该 DLL，可直接跑。</li><li><strong>构建</strong>：若需要本地也执行 <code>pnpm build</code> 且要用字体子集化，再按办法一或办法二确保 DLL 存在即可。</li></ul><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><table tabindex="0"><thead><tr><th>原因</th><th>说明</th></tr></thead><tbody><tr><td>postinstall 用 <code>|| node -v</code></td><td>下载失败时脚本仍返回 0，安装“成功”但 DLL 未下载</td></tr><tr><td>pnpm 10+ 默认不跑依赖脚本</td><td>未配置 allowBuilds/onlyBuiltDependencies 时，cn-font-split 的 postinstall 不会执行</td></tr><tr><td>从 store 恢复不重复跑脚本</td><td>缓存包可能不再执行 postinstall，DLL 一直缺失</td></tr><tr><td>网络 / PowerShell</td><td>GitHub 或 ungh.cc 不可达，或 init.ps1 执行异常，同样会静默失败</td></tr></tbody></table><p><strong>建议</strong>：先执行一次 <code>npx cn-font-split i default</code> 确认能下载到 DLL；若需要长期自动下载，再在 <code>.npmrc</code> 中配置 <code>onlyBuiltDependencies=cn-font-split</code> 并视情况配合 <code>pnpm rebuild</code>。</p>`,53)])])}const g=i(e,[["render",a]]);export{k as __pageData,g as default};
